// // This module generates signals p_l and z based on inputs b and pm1_l. p_l is the complement of the AND of b[1] and b[2], while z is the complement of pm1_l when b[0] is high.
module mul_ppgensign ( p_l, z, b, pm1_l );
output  p_l, z;
input  pm1_l;
input [2:0]  b;
assign p_l = ~(b[1] & b[2]);
assign z = b[0] ? ~pm1_l : ~p_l ;
endmodule
